        "Georgy Zhukov (Western Front)",
        "Ivan Konev (Kalinin Front)",
        "Semyon Timoshenko"
      ],
      "strength": "1,250,000 (including Siberian reserves)"
    }
  },
  "phases": [
    {
      "name": "Initial Typhoon",
      "dates": "October 1941",
      "description": "German forces achieve massive encirclements at Vyazma and Bryansk, capturing 657,000 Soviet prisoners. The road to Moscow appears open."
    },
    {
