{
  "id": "gothic-line",
  "title": "Battle of the Gothic Line",
  "subtitle": "The Final German Defensive Line in Italy",
  "theater": "italy",
  "dates": {
    "start": "1944-08-25",
    "end": "1945-04-21"
  },
  "date_start": "1944-08-25",
  "date_end": "1945-04-21",
  "theatre": "Northern Apennines, Italy",
  "combatants": {
    "axis": {
      "commanders": [
        "Albert Kesselring (to March 1945)",
        "Heinrich von Vietinghoff (from March 1945)"
      ],
