{
  "id": "dieppe",
  "title": "Dieppe Raid (Operation Jubilee)",
  "subtitle": "The Costliest Raid of the Second World War",
  "theater": "western-front",
  "dates": {
    "start": "1942-08-19",
    "end": "1942-08-19"
  },
  "date_start": "1942-08-19",
  "date_end": "1942-08-19",
